/// <summary>Web search and page-fetching tools.</summary>
static class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html,application/xhtml+xml" },
        },
    };

    [Description("Search the web for a query. Returns a JSON array of results with title, url, and snippet.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        try
        {
            // Use DuckDuckGo Lite (HTML) — no API key required
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://lite.duckduckgo.com/lite?q={encoded}";
            var html = await Http.GetStringAsync(url);

            var results = ParseDuckDuckGoLite(html);
            if (results.Count == 0)
                return "No results found.";

            return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch and extract text content from a web page URL. Returns the first ~3000 characters of page text.")]
    public static async Task<string> FetchPageAsync(
        [Description("The URL to fetch")] string url)
    {
        try
        {
            var html = await Http.GetStringAsync(url);
            var text = StripHtml(html);

            const int maxLen = 3000;
            if (text.Length > maxLen)
                text = text[..maxLen] + "\n...(truncated)";

            return text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseDuckDuckGoLite(string html)
    {
        var results = new List<SearchResult>();
        var span = html.AsSpan();

        // DuckDuckGo Lite returns results in <a class="result-link" href="...">Title</a>
        // followed by <td class="result-snippet">Snippet</td>
        var searchPos = 0;
        while (results.Count < 8)
        {
            var linkStart = html.IndexOf("class=\"result-link\"", searchPos, StringComparison.Ordinal);
            if (linkStart < 0) break;

            // Extract URL from href
            var hrefStart = html.LastIndexOf("href=\"", linkStart, Math.Min(linkStart, 200), StringComparison.Ordinal);
            if (hrefStart < 0) { searchPos = linkStart + 1; continue; }
            hrefStart += 6;
            var hrefEnd = html.IndexOf('"', hrefStart);
            if (hrefEnd < 0) break;
            var resultUrl = html[hrefStart..hrefEnd];

            // Extract title (text inside the <a> tag)
            var titleStart = html.IndexOf('>', linkStart) + 1;
            var titleEnd = html.IndexOf("</a>", titleStart, StringComparison.Ordinal);
            var title = titleEnd > titleStart ? StripHtml(html[titleStart..titleEnd]).Trim() : "";

            // Extract snippet
            var snippetMarker = html.IndexOf("result-snippet", titleEnd, StringComparison.Ordinal);
            var snippet = "";
            if (snippetMarker > 0)
            {
                var snippetStart = html.IndexOf('>', snippetMarker) + 1;
                var snippetEnd = html.IndexOf("</td>", snippetStart, StringComparison.Ordinal);
                if (snippetEnd > snippetStart)
                    snippet = StripHtml(html[snippetStart..snippetEnd]).Trim();
            }

            if (!string.IsNullOrWhiteSpace(title) && resultUrl.StartsWith("http"))
            {
                resultUrl = WebUtility.HtmlDecode(resultUrl);
                results.Add(new SearchResult(
                    WebUtility.HtmlDecode(title),
                    resultUrl,
                    WebUtility.HtmlDecode(snippet)));
            }

            searchPos = titleEnd > 0 ? titleEnd : linkStart + 1;
        }

        return results;
    }

    private static string StripHtml(string html)
    {
        var sb = new StringBuilder(html.Length);
        var inTag = false;
        var lastWasSpace = false;

        foreach (var ch in html)
        {
            switch (ch)
            {
                case '<':
                    inTag = true;
                    break;
                case '>':
                    inTag = false;
                    break;
                default:
                    if (!inTag)
                    {
                        var isSpace = char.IsWhiteSpace(ch);
                        if (isSpace && lastWasSpace) continue;
                        sb.Append(isSpace ? ' ' : ch);
                        lastWasSpace = isSpace;
                    }
                    break;
            }
        }

        return WebUtility.HtmlDecode(sb.ToString().Trim());
    }

    private record SearchResult(string Title, string Url, string Snippet);
}

